CREATE TABLE files (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  name TEXT NOT NULL,
  size BIGINT NOT NULL,
  mime_type TEXT NOT NULL,
  path TEXT NOT NULL UNIQUE,
  uploaded_at TIMESTAMPTZ DEFAULT NOW() NOT NULL
);

CREATE INDEX idx_files_uploaded_at ON files(uploaded_at DESC);

-- RLS Policy for anon SELECT
ALTER TABLE files ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public files are viewable by everyone." ON files FOR SELECT USING (true);

-- Delete policy for anon (with trigger for storage cleanup)
CREATE POLICY "Authenticated users can delete own files." ON files FOR DELETE USING (true); -- Adjust for auth
